python3 -c "
import sys, json, os, subprocess
try:
    data = json.load(sys.stdin)
except Exception:
    sys.exit(0)
fp = data.get('tool_input', {}).get('file_path', '')
if not fp.endswith('.json'):
    sys.exit(0)
name = os.path.basename(fp)
schema_map = {
    'run-state.json': 'run-state',
    'decision-log.json': 'decision-log',
    'task-state.json': 'task-state',
    'retrieval-index.json': 'retrieval-index',
}
for phase in ['research','plan','implement','validate']:
    schema_map[f'phase-summary-{phase}.json'] = 'phase-summary'
schema = schema_map.get(name)
if not schema:
    sys.exit(0)
proj = '/home/ewonn/Documents/Personal Projects/ewonn-claude-workflow'
result = subprocess.run(['npx','tsx','src/validator.ts', schema, fp], capture_output=True, text=True, cwd=proj)
if result.stdout:
    print(result.stdout, end='')
if result.returncode != 0:
    print(f'SCHEMA VALIDATION FAILED for {name}: {result.stderr}', file=sys.stderr)
    sys.exit(2)
"
